import heapq

def huffman_codes(freq_table):
    heap = [[freq, [char, ""]] for char, freq in freq_table.items()]
    heapq.heapify(heap)

    while len(heap) > 1:
        lo = heapq.heappop(heap)
        hi = heapq.heappop(heap)
        for pair in lo[1:]:
            pair[1] = '0' + pair[1]
        for pair in hi[1:]:
            pair[1] = '1' + pair[1]
        heapq.heappush(heap, [lo[0] + hi[0]] + lo[1:] + hi[1:])

    return sorted(heap[0][1:], key=lambda p: len(p[1]))

freq = {'a': 45, 'b': 13, 'c': 12, 'd': 16, 'e': 9, 'f': 5}
for char, code in huffman_codes(freq):
    print(f"{char}: {code}")
# 'a' gets the shortest code because it is most frequent

import heapq

def dijkstra(graph, start):
    # graph: dict of {node: [(neighbor, weight), ...]}
    dist = {node: float('inf') for node in graph}
    dist[start] = 0
    pq = [(0, start)]   # (distance, node)

    while pq:
        current_dist, u = heapq.heappop(pq)

        if current_dist > dist[u]:
            continue    # already found a shorter path

        for v, weight in graph[u]:
            new_dist = dist[u] + weight
            if new_dist < dist[v]:
                dist[v] = new_dist
                heapq.heappush(pq, (new_dist, v))

    return dist

graph = {
    'A': [('B', 4), ('C', 2)],
    'B': [('D', 5)],
    'C': [('B', 1), ('D', 8)],
    'D': []
}
print(dijkstra(graph, 'A'))
# {'A': 0, 'B': 3, 'C': 2, 'D': 8}
# A→C→B→D (cost 8) is optimal, not A→B→D (cost 9)

# ✅ Problem must have optimal substructure
# Example: Dijkstra's shortest path (greedy works)
graph = {
    'A': {'B': 1, 'C': 4},
    'B': {'C': 2, 'D': 5},
    'C': {'D': 1},
    'D': {}
}

def dijkstra(graph, start):
    distances = {node: float('inf') for node in graph}
    distances[start] = 0
    unvisited = list(graph.keys())

    while unvisited:
        # ✅ Greedy: Pick closest unvisited node
        current = min(unvisited, key=lambda x: distances[x])  # ✅ Greedy choice [web:198]
        unvisited.remove(current)

        for neighbor, weight in graph[current].items():
            # ✅ Update distance if shorter path found
            distances[neighbor] = min(distances[neighbor], distances[current] + weight)

    return distances

dijkstra(graph, 'A')  # ✅ {'A': 0, 'B': 1, 'C': 3, 'D': 4} (optimal) [web:198]
